from itertools import permutations

class Solution:
    def countNumbersWithUniqueDigits(self, n: int) -> int:
        # Direct enumeration via permutations of digit positions (no closed-form
        # multiplication), independent of the optimal solution's running-product approach.
        if n == 0:
            return 1
        total = 1  # x = 0
        for length in range(1, n + 1):
            for p in permutations(range(10), length):
                if p[0] != 0:
                    total += 1
        return total

