var countNumbersWithUniqueDigits = function(n) {
    if (n === 0) return 1;
    let total = 10;
    let uniq = 9;
    let avail = 9;
    for (let i = 2; i <= n; i++) {
        uniq *= avail;
        total += uniq;
        avail -= 1;
    }
    return total;
};
